                {% set tax_code = tax.description %}
                {% set company_suffix = tax.account_head | replace(tax_code, "") %}

                {# Find the corresponding rates and names from the items child table #}
                {% set ns = namespace(tax_name='', tax_rate=0, found=false) %}
                {% for item in doc.items %}
                    {% if not ns.found and item.custom_tax_code == tax_code %}

                        {# Clean the template name using the dynamically isolated company suffix #}
                        {% set raw_template = item.item_tax_template %}
                        {% set clean_name = raw_template | replace(company_suffix, "") if company_suffix else raw_template %}

                        {% set ns.tax_name = clean_name %}
                        {% set ns.tax_rate = item.custom_tax_rate | float %}
                        {% set ns.found = true %}
                    {% endif %}
                {% endfor %}

                <tr>
                    <td style="border: 1px solid #ffffff !important; border-right: none !important; background: #ffffff !important; background-color: #ffffff !important;"></td>
                    <td>
