                            <strong>{{ ns.tax_name }}</strong> 
                            <small class="text-muted"> – {{ tax_code }}</small>
                        {% else %}
                            <strong>{{ tax_code }}</strong>
                        {% endif %}

                    </td>
                    <td class="text-right">
                        {{ ns.tax_rate }}%
                    </td>
                    <td class="text-right">
                        {# Computes taxable amount backwards using the corrected rate from items #}
                        {% if ns.tax_rate and ns.tax_rate != 0 %}
                            {% set calculated_taxable = (tax.tax_amount_after_discount_amount / ns.tax_rate) * 100 %}
                            {{ frappe.format(calculated_taxable, tax.meta.get_field('tax_amount'), doc) }}
                        {% else %}
                            {{ frappe.format(0, tax.meta.get_field('tax_amount'), doc) }}
                        {% endif %}
                    </td>
                    <td class="text-right">
                        {{ frappe.format(tax.tax_amount_after_discount_amount, tax.meta.get_field('tax_amount_after_discount_amount'), doc) }}
                    </td>
                </tr>
            {% endfor %}
        </tbody>
